{
  "command": "duckdb '/workspace/DataAgentBench/query_GITHUB_REPOS/query_dataset/repo_artifacts.db' \"SELECT repo_name, COUNT(*) as cnt FROM commits GROUP BY repo_name ORDER BY cnt DESC LIMIT 20;\"",
  "description": "Top repos by commit count"
}

{
  "command": "duckdb -readonly '/workspace/DataAgentBench/query_GITHUB_REPOS/query_dataset/repo_artifacts.db' \"SELECT repo_name, COUNT(*) as cnt FROM commits GROUP BY repo_name ORDER BY cnt DESC LIMIT 30;\"",
  "description": "Top repos by commits (read-only)"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_GITHUB_REPOS/query_dataset/repo_metadata.db' \"SELECT repo_name, language_description FROM languages WHERE repo_name IN ('torvalds/linux','apple/swift','twbs/bootstrap','Microsoft/vscode','facebook/react','tensorflow/tensorflow');\"",
  "description": "Check languages for top repos"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_GITHUB_REPOS/query_dataset/repo_metadata.db' \"SELECT repo_name, language_description FROM languages WHERE repo_name = 'torvalds/linux';\"",
  "description": "Check torvalds/linux language"
}

{
  "command": "duckdb -readonly '/workspace/DataAgentBench/query_GITHUB_REPOS/query_dataset/repo_artifacts.db' \"SELECT COUNT(DISTINCT repo_name) FROM commits;\"",
  "description": "Count distinct repos in commits"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_GITHUB_REPOS/query_dataset/repo_metadata.db' \"SELECT repo_name, language_description FROM languages WHERE repo_name LIKE '%linux%' OR repo_name LIKE 'torvalds%';\"",
  "description": "Check linux repo languages"
}
